section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/argocd-gitops.json",
  "type": "object",
  "required": [
    "artefact_id",
    "environments_modeled_as",
    "self_heal_enabled",
    "application_management",
    "appproject_per_team",
    "sync_waves_set",
    "notifications_wired",
    "revision_history_limit",
    "owner"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "stable id"
    },
    "environments_modeled_as": {
      "type": "string",
      "description": "enum: folders | branches | branches"
    },
    "self_heal_enabled": {
      "type": "boolean",
      "description": "true"
    },
    "application_management": {
      "type": "string",
      "description": "enum: app-of-apps | applicationset | manual"
    },
    "appproject_per_team": {
      "type": "boolean",
      "description": "true (no default project for production)"
    },
    "sync_waves_set": {
      "type": "boolean",
      "description": "true"
    },
    "notifications_wired": {
      "type": "array",
      "description": "non-empty: ['on-sync-failed', 'on-health-degraded']"
    },
    "revision_history_limit": {
      "type": "integer",
      "description": ">= 5"
    },
    "owner": {
      "type": "string",
      "description": "single named handle"
    }
  }
}
